import{_ as e,o as t,c as i,a2 as l}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Comment 评论","description":"","frontmatter":{"title":"Comment 评论","stage":"intermediate","direction":"interaction-design","tags":["interaction-patterns","collaboration","comment"]},"headers":[],"relativePath":"03-interaction-design/notes/06-interaction-patterns/05-collaboration/comment.md","filePath":"03-interaction-design/notes/06-interaction-patterns/05-collaboration/comment.md","lastUpdated":null}'),r={name:"03-interaction-design/notes/06-interaction-patterns/05-collaboration/comment.md"};function d(n,a,o,s,h,c){return t(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="comment-评论" tabindex="-1">Comment 评论 <a class="header-anchor" href="#comment-评论" aria-label="Permalink to &quot;Comment 评论&quot;">​</a></h1><p>Comment 是由明确主体创建、附着于内容或内容片段、可被回复和治理的协作记录。评论系统不仅保存一段文字，还要维护线程关系、锚点版本、编辑与删除历史、解决状态和每个动作的授权。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>本文聚焦：</p><ul><li>评论、回复与线程的身份模型。</li><li>文档、画布、时间轴和对象字段上的锚点。</li><li>编辑、删除、解决、重开与并发操作。</li><li>作者、对象成员、版主和外部协作者的权限边界。</li><li>深链、通知、无障碍、审计与数据保留。</li></ul><p>前置知识：</p><ul><li>能区分业务对象、内容版本和稳定对象 ID。</li><li>理解可见入口与服务端授权不是同一件事。</li><li>能为异步写入处理失败、重试、冲突和离线恢复。</li></ul><p>评论不是对象正文的替代品。已经形成的决定应写入权威内容或决策记录；评论线程保留讨论过程与来源。</p><h2 id="评论资源模型" tabindex="-1">评论资源模型 <a class="header-anchor" href="#评论资源模型" aria-label="Permalink to &quot;评论资源模型&quot;">​</a></h2><p>一个可维护的评论至少包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>作用</th><th>关键边界</th></tr></thead><tbody><tr><td><code>comment_id</code></td><td>评论稳定身份</td><td>改文案、换锚点后不变</td></tr><tr><td><code>container_id</code></td><td>所属文档、设计稿或工单</td><td>决定主要授权范围</td></tr><tr><td><code>thread_id</code></td><td>所属线程</td><td>根评论与回复共享</td></tr><tr><td><code>parent_comment_id</code></td><td>直接回复对象</td><td>可选，不能形成环</td></tr><tr><td><code>author_id</code></td><td>创建主体稳定 ID</td><td>不用显示名作身份</td></tr><tr><td><code>body</code></td><td>当前可展示内容</td><td>富文本需安全解析</td></tr><tr><td><code>anchor</code></td><td>指向整体对象或片段</td><td>必须包含版本与恢复策略</td></tr><tr><td><code>created_at</code></td><td>服务端创建时间</td><td>不信任客户端时间</td></tr><tr><td><code>updated_at</code></td><td>最近内容修改时间</td><td>与状态变更时间分开</td></tr><tr><td><code>version</code></td><td>并发控制版本</td><td>编辑时比较</td></tr><tr><td><code>resolution</code></td><td>open、resolved 等</td><td>属于线程，不属于单条回复</td></tr><tr><td><code>deleted_state</code></td><td>active、tombstone、purged</td><td>删除不等于所有痕迹消失</td></tr><tr><td><code>visibility</code></td><td>对象成员、受邀人、内部等</td><td>读取时重新授权</td></tr></tbody></table><p>W3C Web Annotation Data Model 将注释建模为 Body 与 Target 的关联，并提供 selector 与 state 表达目标片段和目标版本。产品可以借鉴这个结构，不必为了实现评论而完整采用 JSON-LD。</p><h2 id="线程与回复" tabindex="-1">线程与回复 <a class="header-anchor" href="#线程与回复" aria-label="Permalink to &quot;线程与回复&quot;">​</a></h2><h3 id="根评论" tabindex="-1">根评论 <a class="header-anchor" href="#根评论" aria-label="Permalink to &quot;根评论&quot;">​</a></h3><p>根评论建立主题、锚点和初始可见范围。回复继承线程锚点，除非产品明确支持回复附着到另一个片段。让每条回复各自漂移到不同锚点，会使“解决线程”没有清晰对象。</p><h3 id="回复层级" tabindex="-1">回复层级 <a class="header-anchor" href="#回复层级" aria-label="Permalink to &quot;回复层级&quot;">​</a></h3><p>深层嵌套会同时增加：</p><ul><li>窄屏缩进。</li><li>阅读顺序复杂度。</li><li>通知目标歧义。</li><li>删除父评论后的展示难度。</li><li>分页和虚拟化成本。</li></ul><p>常见选择：</p><table tabindex="0"><thead><tr><th>模型</th><th>适用</th><th>代价</th></tr></thead><tbody><tr><td>单层线程</td><td>围绕一个锚点短讨论</td><td>不能视觉表达回复分支</td></tr><tr><td>两层回复</td><td>需要回复某人但保持主题平坦</td><td>同层时间线仍可能交错</td></tr><tr><td>任意嵌套</td><td>论坛式长期讨论</td><td>移动端、排序和无障碍复杂</td></tr><tr><td>子线程</td><td>某条回复产生独立议题</td><td>需要线程间导航与状态</td></tr></tbody></table><p>协作文档通常优先单层或有限层级，并用“回复某人”表达局部语境。</p><h3 id="排序" tabindex="-1">排序 <a class="header-anchor" href="#排序" aria-label="Permalink to &quot;排序&quot;">​</a></h3><p>线程内部通常按服务端创建序稳定排序；相同时间使用 <code>comment_id</code> 或序列号消除不确定性。根线程可按锚点位置、最近活动或未解决优先排序，但切换排序不能改变线程身份。</p><p>新回复插入后不能让键盘焦点和阅读位置突然跳到列表顶部。</p><h2 id="锚点不是屏幕坐标" tabindex="-1">锚点不是屏幕坐标 <a class="header-anchor" href="#锚点不是屏幕坐标" aria-label="Permalink to &quot;锚点不是屏幕坐标&quot;">​</a></h2><h3 id="锚点组成" tabindex="-1">锚点组成 <a class="header-anchor" href="#锚点组成" aria-label="Permalink to &quot;锚点组成&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C[&quot;Comment&quot;] --&gt; T[&quot;Target 业务对象&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T --&gt; V[&quot;Target version&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T --&gt; S[&quot;Selector 目标片段&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; P[&quot;稳定节点 ID&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; Q[&quot;文本引用与前后文&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; G[&quot;画布对象与局部坐标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V --&gt; R[&quot;重定位策略&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>单纯保存 <code>x=420, y=180</code> 只能对应某个缩放、布局和版本。可靠锚点应先识别稳定内容节点，再用位置或文本选择器细化。</p><h3 id="文本锚点" tabindex="-1">文本锚点 <a class="header-anchor" href="#文本锚点" aria-label="Permalink to &quot;文本锚点&quot;">​</a></h3><p>可组合：</p><ul><li>文档或块的稳定 ID。</li><li>内容版本 ID。</li><li>选中文本的标准化引用。</li><li>选区前缀与后缀。</li><li>起止字符位置。</li></ul><p>Text Position Selector 体积小但对前文插入敏感；Text Quote Selector 用 exact、prefix、suffix 重定位，但重复文本可能产生多个匹配。二者结合并记录版本，可提高恢复概率。</p><p>字符位置要说明计数方式。W3C 模型以 Unicode code point 表达位置，并建议不要截断 grapheme cluster。JavaScript 字符串索引基于 UTF-16 code unit，不能直接假设与该模型相同。</p><h3 id="画布锚点" tabindex="-1">画布锚点 <a class="header-anchor" href="#画布锚点" aria-label="Permalink to &quot;画布锚点&quot;">​</a></h3><p>优先保存图层、节点或组件实例 ID；局部归一化坐标只表达节点内部位置。节点移动时评论跟随节点，节点删除时线程进入失联状态。</p><p>若评论附着在像素渲染结果，还需记录画布版本、页面或帧 ID、缩放无关坐标和可选截图摘要。截图只能帮助回忆，不能替代可授权的目标数据。</p><h3 id="时间媒体锚点" tabindex="-1">时间媒体锚点 <a class="header-anchor" href="#时间媒体锚点" aria-label="Permalink to &quot;时间媒体锚点&quot;">​</a></h3><p>音视频评论保存媒体 ID、版本和时间范围。转码后若时间轴改变，需要媒资系统提供映射；不要按播放器当前像素位置保存。</p><h3 id="锚点失联" tabindex="-1">锚点失联 <a class="header-anchor" href="#锚点失联" aria-label="Permalink to &quot;锚点失联&quot;">​</a></h3><p>目标删除、文本大改或版本不可读时：</p><ul><li>保留线程，不静默移动到最近位置。</li><li>标记“原位置已变化”。</li><li>若可授权，显示原引用摘要和历史版本入口。</li><li>允许有权限的人重新锚定。</li><li>重新锚定记录旧锚点和操作者。</li></ul><h2 id="线程状态" tabindex="-1">线程状态 <a class="header-anchor" href="#线程状态" aria-label="Permalink to &quot;线程状态&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stateDiagram-v2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [*] --&gt; Open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Open --&gt; Resolved: &quot;有权限者确认议题已处理&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Resolved --&gt; Reopened: &quot;后续变化使问题再次成立&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Reopened --&gt; Resolved: &quot;再次确认&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Open --&gt; Archived: &quot;容器归档或策略迁移&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Resolved --&gt; Archived</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Archived --&gt; Open: &quot;对象恢复且策略允许&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="open" tabindex="-1">Open <a class="header-anchor" href="#open" aria-label="Permalink to &quot;Open&quot;">​</a></h3><p>线程仍需要关注。新建线程默认 open，但“评论”不一定都代表待办；产品可提供纯讨论与待解决两种动机，避免所有闲聊都进入未解决统计。</p><h3 id="resolved" tabindex="-1">Resolved <a class="header-anchor" href="#resolved" aria-label="Permalink to &quot;Resolved&quot;">​</a></h3><p>解决表示讨论对应的问题已处理或无需处理，不代表评论被删除。需要记录：</p><ul><li>解决人。</li><li>解决时间。</li><li>可选解决说明。</li><li>当时目标版本。</li></ul><p>默认折叠已解决线程可以减少噪声，但必须可查找和回看。</p><h3 id="reopened" tabindex="-1">Reopened <a class="header-anchor" href="#reopened" aria-label="Permalink to &quot;Reopened&quot;">​</a></h3><p>重开不是把 <code>resolved=false</code> 覆盖掉。它是新的状态事件，需要保留重开人、原因和版本。若内容修改使原问题重新出现，可由人明确重开；系统自动重开需有可解释规则。</p><h3 id="archived" tabindex="-1">Archived <a class="header-anchor" href="#archived" aria-label="Permalink to &quot;Archived&quot;">​</a></h3><p>对象归档不一定删除评论。归档线程通常只读，并继承对象保留策略。</p><h2 id="编辑" tabindex="-1">编辑 <a class="header-anchor" href="#编辑" aria-label="Permalink to &quot;编辑&quot;">​</a></h2><h3 id="允许范围" tabindex="-1">允许范围 <a class="header-anchor" href="#允许范围" aria-label="Permalink to &quot;允许范围&quot;">​</a></h3><p>作者可在策略允许期内编辑正文；版主可以处理违规内容，但不应伪装成作者编辑。编辑锚点、正文和可见范围是不同风险操作。</p><h3 id="编辑历史" tabindex="-1">编辑历史 <a class="header-anchor" href="#编辑历史" aria-label="Permalink to &quot;编辑历史&quot;">​</a></h3><p>对协作决策、合规或支持场景，保存：</p><ul><li>版本号。</li><li>修改者。</li><li>修改时间。</li><li>修改前后内容或差异。</li><li>修改原因（策略要求时）。</li></ul><p>普通社交场景也至少标记“已编辑”。若历史可查看，要沿用评论读取权限，不能让撤权用户从历史接口读取旧内容。</p><h3 id="并发编辑" tabindex="-1">并发编辑 <a class="header-anchor" href="#并发编辑" aria-label="Permalink to &quot;并发编辑&quot;">​</a></h3><p>客户端提交 <code>comment_id</code>、期望版本和新正文。服务端若发现版本已变化：</p><ul><li>返回冲突与当前版本。</li><li>保留用户本地草稿。</li><li>提供比较、复制或重新应用。</li><li>不做最后写入者静默覆盖。</li></ul><p>HTTP 条件请求可使用 ETag 与 <code>If-Match</code> 表达前置版本，但业务仍要定义冲突响应和恢复界面。</p><h2 id="删除与内容治理" tabindex="-1">删除与内容治理 <a class="header-anchor" href="#删除与内容治理" aria-label="Permalink to &quot;删除与内容治理&quot;">​</a></h2><h3 id="软删除-tombstone" tabindex="-1">软删除 Tombstone <a class="header-anchor" href="#软删除-tombstone" aria-label="Permalink to &quot;软删除 Tombstone&quot;">​</a></h3><p>线程有回复、审计要求或引用关系时，删除正文但保留占位：</p><ul><li>“该评论已由作者删除。”</li><li>评论 ID、线程关系和必要时间仍存在。</li><li>不在普通界面显示已删除正文。</li><li>回复顺序保持。</li></ul><h3 id="硬删除-purge" tabindex="-1">硬删除 Purge <a class="header-anchor" href="#硬删除-purge" aria-label="Permalink to &quot;硬删除 Purge&quot;">​</a></h3><p>法律请求、敏感信息泄露或保留期结束可能要求清除正文、附件、搜索索引和派生缓存。审计记录只保留允许保留的最小事件，不应通过“审计”无限保存被要求删除的内容。</p><h3 id="版主移除" tabindex="-1">版主移除 <a class="header-anchor" href="#版主移除" aria-label="Permalink to &quot;版主移除&quot;">​</a></h3><p>与作者删除区分。界面可以说明“因违反政策被移除”，但不泄露审核内部细节。申诉路径由治理政策决定。</p><h3 id="附件" tabindex="-1">附件 <a class="header-anchor" href="#附件" aria-label="Permalink to &quot;附件&quot;">​</a></h3><p>删除评论时同时处理附件引用、预览、CDN、下载 URL 和病毒扫描记录。只删数据库正文会留下可访问附件。</p><h2 id="权限模型" tabindex="-1">权限模型 <a class="header-anchor" href="#权限模型" aria-label="Permalink to &quot;权限模型&quot;">​</a></h2><p>每个动作单独授权：</p><table tabindex="0"><thead><tr><th>动作</th><th>典型主体</th><th>服务端检查</th></tr></thead><tbody><tr><td>读取线程</td><td>对象可读者且满足评论可见范围</td><td>当前对象权限、线程范围、目标版本</td></tr><tr><td>创建根评论</td><td>可评论者</td><td>对象状态、锚点可见、限流</td></tr><tr><td>回复</td><td>可评论者</td><td>线程仍可回复、父评论可读</td></tr><tr><td>编辑正文</td><td>作者或受控版主</td><td>当前版本、编辑期限、对象策略</td></tr><tr><td>删除正文</td><td>作者、版主或数据治理</td><td>回复关系、保留策略、删除类型</td></tr><tr><td>解决线程</td><td>议题负责人、对象编辑者等</td><td>线程状态、业务角色</td></tr><tr><td>重开线程</td><td>可解决者或评论者，依产品规则</td><td>当前目标与状态</td></tr><tr><td>重新锚定</td><td>对象编辑者</td><td>新旧目标都可读写</td></tr></tbody></table><p>作者身份不自动赋予永久权限。作者离开组织后，评论可能保留署名快照，但其账户不能继续读取或修改。</p><h2 id="富文本与安全" tabindex="-1">富文本与安全 <a class="header-anchor" href="#富文本与安全" aria-label="Permalink to &quot;富文本与安全&quot;">​</a></h2><ul><li>正文采用结构化富文本或受控 Markdown；服务端清理不可信 HTML。</li><li>链接采用安全协议白名单，外部链接明确目标。</li><li>图片和附件先授权再下载，短期 URL 不进入正文。</li><li><code>@mention</code> 保存身份节点，不靠重新解析显示字符串。</li><li>代码块、表格和引用保留语义与键盘可访问性。</li><li>评论搜索索引遵守当前对象权限与删除状态。</li><li>限制体积、回复频率和附件数量，防止资源滥用。</li></ul><h2 id="离线、乐观更新与失败" tabindex="-1">离线、乐观更新与失败 <a class="header-anchor" href="#离线、乐观更新与失败" aria-label="Permalink to &quot;离线、乐观更新与失败&quot;">​</a></h2><h3 id="临时评论" tabindex="-1">临时评论 <a class="header-anchor" href="#临时评论" aria-label="Permalink to &quot;临时评论&quot;">​</a></h3><p>发送时可先显示带 <code>client_request_id</code> 的临时项，但必须标为发送中。服务端成功后用正式 <code>comment_id</code> 替换；重试复用请求 ID，避免重复评论。</p><h3 id="失败" tabindex="-1">失败 <a class="header-anchor" href="#失败" aria-label="Permalink to &quot;失败&quot;">​</a></h3><p>发送失败保留正文、锚点和附件选择，提供重试或复制。失败评论不应触发真实通知，也不能被其他客户端看到。</p><h3 id="乱序" tabindex="-1">乱序 <a class="header-anchor" href="#乱序" aria-label="Permalink to &quot;乱序&quot;">​</a></h3><p>WebSocket 推送和 POST 响应可能乱序。以服务端序列和评论 ID 去重，不能因先收到推送再收到响应而显示两条。</p><h2 id="案例一-合同段落上的审阅线程" tabindex="-1">案例一：合同段落上的审阅线程 <a class="header-anchor" href="#案例一-合同段落上的审阅线程" aria-label="Permalink to &quot;案例一：合同段落上的审阅线程&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>合同文档有稳定块 ID 和版本号。法务选择一句“服务可随时终止”创建评论，另一名编辑者随后在该段前插入两段文字，并把目标句改为“服务可提前 30 日通知后终止”。</p><h3 id="锚点与线程" tabindex="-1">锚点与线程 <a class="header-anchor" href="#锚点与线程" aria-label="Permalink to &quot;锚点与线程&quot;">​</a></h3><p>根评论保存：</p><ul><li>文档 ID <code>contract-42</code>。</li><li>版本 <code>v18</code>。</li><li>段落块 ID <code>clause-termination</code>。</li><li>exact 引用、前后文。</li><li>在标准化段落中的位置。</li></ul><p>插入前文不会影响块 ID。目标句修改后 exact 不再匹配，系统用块 ID 定位段落，并标记原引用已变化。线程显示原引用摘要和当前段落。</p><h3 id="解决" tabindex="-1">解决 <a class="header-anchor" href="#解决" aria-label="Permalink to &quot;解决&quot;">​</a></h3><p>法务回复“30 日符合要求”，文档所有者将线程解决，记录版本 <code>v21</code>。之后另一编辑者把期限改为 7 日，系统不直接伪装成“仍已解决”；规则可以提示“解决后的锚点内容已变化”，由有权限者决定重开。</p><h3 id="编辑和删除" tabindex="-1">编辑和删除 <a class="header-anchor" href="#编辑和删除" aria-label="Permalink to &quot;编辑和删除&quot;">​</a></h3><p>作者编辑回复时保存历史。删除根评论后线程已有回复，因此显示 tombstone，回复仍可理解。若原评论包含误贴的个人证件号，治理操作执行 purge，同时清理版本历史、搜索索引和通知预览。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>在段前插入、段内修改、块移动和块删除条件下检查锚点。</li><li>两人同时编辑同一回复，确认冲突不会静默覆盖。</li><li>解决后修改目标，检查状态提示。</li><li>外部审阅者撤权后无法从深链或历史接口读取线程。</li><li>键盘可从段落锚点进入线程并返回原段落。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若只保存字符位置，段前插入会把评论挂到错误句子，且界面看似正常。重定位必须优先验证块身份和文本引用；无法确定时进入失联状态，不能猜最近位置。</p><h2 id="案例二-客户工单中的内部与外部评论" tabindex="-1">案例二：客户工单中的内部与外部评论 <a class="header-anchor" href="#案例二-客户工单中的内部与外部评论" aria-label="Permalink to &quot;案例二：客户工单中的内部与外部评论&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>支持工单同时包含客户可见回复和内部备注。客服、值班工程师、客户联系人和外部供应商具有不同可见范围。工单关闭后评论只读，重新打开后可继续讨论。</p><h3 id="可见范围" tabindex="-1">可见范围 <a class="header-anchor" href="#可见范围" aria-label="Permalink to &quot;可见范围&quot;">​</a></h3><p>每条根评论在创建时明确：</p><ul><li><code>customer-visible</code>：客户联系人和内部处理者可读。</li><li><code>internal</code>：组织内部授权人员可读。</li><li><code>vendor-thread</code>：指定供应商与内部人员可读。</li></ul><p>回复继承线程可见范围，不能在内部线程中单条切换为客户可见，避免上下文泄露。需要对外发送时，创建新的客户可见回复并明确引用经过审查的内容。</p><h3 id="权限与通知" tabindex="-1">权限与通知 <a class="header-anchor" href="#权限与通知" aria-label="Permalink to &quot;权限与通知&quot;">​</a></h3><p>供应商被移除后，历史线程读取立即失效；已发送邮件通知只包含最小摘要，不包含完整内部内容。客服可以解决“等待日志”线程，客户不能解决内部线程。</p><p>工单关闭后新评论接口拒绝写入，客户端保留草稿并解释状态已变化。重新打开不自动恢复已撤销供应商权限。</p><h3 id="删除与审计" tabindex="-1">删除与审计 <a class="header-anchor" href="#删除与审计" aria-label="Permalink to &quot;删除与审计&quot;">​</a></h3><p>客户可以按政策删除自己尚未被处理的消息；内部备注遵守支持记录保留。版主移除辱骂内容时保留治理事件，但不让普通客服查看原文。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>四种身份分别读取同一工单和通知深链。</li><li>尝试在内部线程创建外部可见回复。</li><li>在输入期间关闭工单，确认草稿恢复。</li><li>移除供应商后检查缓存、搜索和附件 URL。</li><li>删除父评论后确认线程关系与审计最小化。</li></ul><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>如果客户端用红色区分内部备注，但接口返回所有评论，客户仍可能从响应或辅助技术读取。可见范围必须在服务端查询与推送阶段过滤，颜色只负责提示作者。</p><h2 id="无障碍与键盘" tabindex="-1">无障碍与键盘 <a class="header-anchor" href="#无障碍与键盘" aria-label="Permalink to &quot;无障碍与键盘&quot;">​</a></h2><ul><li>评论列表使用有意义的列表或文章结构，作者、时间、正文和操作关系可程序化理解。</li><li>“已编辑”“已解决”“原位置已变化”用文本表达。</li><li>锚点按钮具有可识别名称，例如“打开第 4 段的 2 条评论”。</li><li>打开侧栏后焦点进入线程标题或首个合理位置；关闭后返回原锚点。</li><li>新回复成功可用简短状态消息，不把整条评论在 live region 中重复播报。</li><li>操作菜单支持键盘并在关闭后恢复焦点。</li><li>无限列表加载新回复时保持当前阅读位置。</li><li>200% 文本缩放下不依赖横向缩进表达回复层级。</li></ul><h2 id="观测与调试" tabindex="-1">观测与调试 <a class="header-anchor" href="#观测与调试" aria-label="Permalink to &quot;观测与调试&quot;">​</a></h2><h3 id="关键观测" tabindex="-1">关键观测 <a class="header-anchor" href="#关键观测" aria-label="Permalink to &quot;关键观测&quot;">​</a></h3><ul><li>根评论创建、有效回复和解决所需时间。</li><li>锚点失联与重新锚定比例，按内容类型和版本操作分组。</li><li>编辑冲突、重复发送和离线重试。</li><li>解决后重开及目标变更提示。</li><li>权限拒绝、撤权后访问和缓存泄露告警。</li><li>删除类型、索引清理延迟和附件残留检查。</li></ul><p>评论数量不是协作质量。大量评论可能来自结构不清或自动通知噪声。</p><h3 id="调试顺序" tabindex="-1">调试顺序 <a class="header-anchor" href="#调试顺序" aria-label="Permalink to &quot;调试顺序&quot;">​</a></h3><ol><li>固定主体、容器、线程和目标版本。</li><li>检查读取与动作权限。</li><li>检查锚点组成、标准化和重定位结果。</li><li>检查评论版本、状态事件和并发前置条件。</li><li>检查推送去重与排序。</li><li>检查删除后的正文、历史、索引和附件。</li><li>复测焦点、状态消息和窄屏布局。</li></ol><h2 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h2><ol><li>评论创建后目标块被移动、修改或删除。</li><li>两人同时编辑同一评论。</li><li>POST 响应丢失但推送已到达。</li><li>线程解决时另一人新增回复。</li><li>对象权限在侧栏打开期间撤销。</li><li>删除含附件与 mention 的根评论。</li><li>长线程分页时父评论位于上一页。</li><li>离线草稿恢复到已归档对象。</li></ol><h2 id="综合练习-实现可治理的锚点线程" tabindex="-1">综合练习：实现可治理的锚点线程 <a class="header-anchor" href="#综合练习-实现可治理的锚点线程" aria-label="Permalink to &quot;综合练习：实现可治理的锚点线程&quot;">​</a></h2><p>为支持文本选区评论的协作文档设计：</p><ol><li>评论、线程、状态事件和编辑版本数据模型。</li><li>文本锚点与重定位算法的输入输出。</li><li>open、resolved、reopened、archived 转移规则。</li><li>作者删除、版主移除和治理清除策略。</li><li>角色—动作授权矩阵。</li><li>离线、并发、推送乱序和撤权测试。</li><li>键盘、屏幕阅读器与长线程验收。</li></ol><p>验收标准：</p><ul><li>评论身份、目标身份和显示名称彼此独立。</li><li>锚点无法可靠恢复时不会静默挂到错误位置。</li><li>编辑冲突保留双方内容。</li><li>解决与删除都有可追踪状态事件。</li><li>回复不会绕过根线程可见范围。</li><li>撤权后深链、搜索、推送与附件同时失效。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/TR/annotation-model/" target="_blank" rel="noreferrer">W3C：Web Annotation Data Model</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/TR/selectors-states/" target="_blank" rel="noreferrer">W3C：Selectors and States</a>（访问日期：2026-07-18）</li><li><a href="https://docs.github.com/en/rest/issues/comments?apiVersion=2022-11-28" target="_blank" rel="noreferrer">GitHub Docs：REST API Endpoints for Issue Comments</a>（访问日期：2026-07-18）</li><li><a href="https://www.rfc-editor.org/rfc/rfc9110.html#name-preconditions" target="_blank" rel="noreferrer">RFC 9110：HTTP Semantics — Preconditions</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/status-messages.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 4.1.3 Status Messages</a>（访问日期：2026-07-18）</li></ul>`,135)])])}const b=e(r,[["render",d]]);export{u as __pageData,b as default};
